#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L;
        uint64_t V;
        scanf("%d %llu", &L, &V);
        uint32_t count = 0;
        uint64_t min = (1ULL << (L - 1));
        uint64_t max = (1ULL << L) - 1;
        for (uint64_t num = min; num <= max; num++) {
            uint64_t divpro = num;
            int len = 0;
            uint64_t temp = num;
            while (temp) {
                len++;
                temp /= 10;
            }
            temp = num;
            int i = 0;
            while (i < len - 1) {
                int digit = temp % 10;
                temp /= 10;
                if (i % 2 == 0) {
                    if (digit == 0) break;
                    divpro /= digit;
                } else {
                    divpro *= digit;
                }
                i++;
            }
            if (i == len - 1 && divpro == V) count++;
        }
        printf("%u\n", count);
    }
    return 0;
}

